/**
 * @summary Get recent records activity
 */
export const getGetRecentActivityUrl = (params?: GetRecentActivityParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/dashboard/recent?${stringifiedParams}`
    : `/api/dashboard/recent`;
};

export const getRecentActivity = async (
  params?: GetRecentActivityParams,
  options?: RequestInit,
): Promise<Record[]> => {
  return customFetch<Record[]>(getGetRecentActivityUrl(params), {
    ...options,
    method: "GET",
  });
};

